parameters.functionCode:
// Parse classifier response and attach to context
const item = $input.first();
let classification;
try {
  const content = item.json.body?.content || item.json.content;
  const text = Array.isArray(content) ? content.find(b => b.type === 'text')?.text : content;
  classification = JSON.parse(text.replace(/```json|```/g, '').trim());
} catch(e) {
  classification = { document_type: 'OTHER', confidence: 0.0, reasoning: 'Parse error: ' + e.message };
}
return [{
  json: {
    ...item.json,
    classification
  }
}];

// Validation Agent: schema + confidence checks
const item = $input.first();
const { classification, textract_text, comprehend_entities } = item.json;
const confidence = classification?.confidence || 0;
const docType = classification?.document_type || 'OTHER';

const schemaChecks = {
  BANK_STATEMENT: ['account_number', 'balance', 'transaction'],
  LOAN_APPLICATION: ['applicant_name', 'loan_amount', 'income'],
  ONBOARDING_FORM: ['name', 'address', 'id_number'],
  OTHER: []
};

const requiredFields = schemaChecks[docType] || [];
const missingFields = requiredFields.filter(f =>
  !(textract_text || '').toLowerCase().includes(f.toLowerCase())
);

const valid = missingFields.length === 0 && confidence >= 0.7;
const needsHITL = !valid || confidence < 0.7;

return [{
  json: {
    ...item.json,
    validation: {
      valid,
      needs_hitl: needsHITL,
      missing_fields: missingFields,
      confidence_gate_passed: confidence >= 0.7,
      checked_at: new Date().toISOString()
    }
  }
}];

// Routing Agent: determines destination storage zone
const item = $input.first();
const docType = item.json.classification?.document_type || 'OTHER';
const confidence = item.json.classification?.confidence || 0;

const routingMap = {
  BANK_STATEMENT:   { zone: 'bronze', downstream: ['aurora_rds', 'elasticsearch'], priority: 'standard' },
  LOAN_APPLICATION: { zone: 'bronze', downstream: ['aurora_rds', 'redshift'], priority: 'high' },
  ONBOARDING_FORM:  { zone: 'bronze', downstream: ['aurora_rds'], priority: 'standard' },
  OTHER:            { zone: 'bronze', downstream: ['elasticsearch'], priority: 'low' }
};

const routing = routingMap[docType] || routingMap.OTHER;

return [{
  json: {
    ...item.json,
    routing: {
      ...routing,
      routed_at: new Date().toISOString()
    }
  }
}];

// Silver Zone: cleanse, deduplicate, normalise
const item = $input.first();
const raw = item.json;

// Simulate deduplication hash
const crypto = require('crypto');
const contentHash = crypto.createHash('sha256')
  .update(JSON.stringify(raw.classification) + raw.s3_key)
  .digest('hex');

const silver = {
  correlation_id: raw.correlation_id,
  content_hash: contentHash,
  document_type: raw.classification.document_type,
  confidence: raw.classification.confidence,
  entities: raw.comprehend_entities || [],
  extracted_fields: raw.textract_fields || {},
  routing: raw.routing,
  processed_at: new Date().toISOString(),
  zone: 'silver'
};

return [{ json: { ...raw, silver } }];

// Gold Zone: business aggregates
const item = $input.first();
const silver = item.json.silver;

const gold = {
  correlation_id: silver.correlation_id,
  document_type: silver.document_type,
  entity_summary: {
    persons:       silver.entities.filter(e => e.Type === 'PERSON').map(e => e.Text),
    organizations: silver.entities.filter(e => e.Type === 'ORGANIZATION').map(e => e.Text),
    amounts:       silver.entities.filter(e => e.Type === 'QUANTITY').map(e => e.Text),
    dates:         silver.entities.filter(e => e.Type === 'DATE').map(e => e.Text)
  },
  risk_indicators: {
    high_value: silver.entities.some(e => e.Type === 'QUANTITY' && parseFloat(e.Text.replace(/[^0-9.]/g,'')) > 100000),
    multiple_entities: silver.entities.filter(e => e.Type === 'PERSON').length > 3
  },
  aggregated_at: new Date().toISOString(),
  zone: 'gold'
};

return [{ json: { ...item.json, gold } }];

