=INSERT INTO dw_documents (
  correlation_id, document_type, confidence, processed_date,
  entity_count, has_high_value_flag
)
VALUES (
  '{{ $json.gold.correlation_id }}',
  '{{ $json.gold.document_type }}',
  {{ $json.silver.confidence }},
  CURRENT_DATE,
  {{ ($json.gold.entity_summary.persons || []).length + ($json.gold.entity_summary.organizations || []).length }},
  {{ $json.gold.risk_indicators.high_value }}
)
ON CONFLICT DO NOTHING;

